query:
-- 刪除所有與測試客戶相關的 demands
DELETE FROM demands 
WHERE clientId IN (
  SELECT id FROM clients 
  WHERE name LIKE '%測試%' OR name LIKE '%test%'
);

-- 刪除所有測試相關的 demands（根據 note 或 location）
DELETE FROM demands 
WHERE note LIKE '%測試%' OR location LIKE '%測試%';

